/* ══════════════════════════════════════════════════════════════
   LOCAL STORAGE CACHE (offline fallback + speed)
══════════════════════════════════════════════════════════════ */
const lsK=t=>"lg_"+t;
const lsG=t=>{try{return JSON.parse(localStorage.getItem(lsK(t))||"[]");}catch{return[];}};
const lsS=(t,v)=>localStorage.setItem(lsK(t),JSON.stringify(v));

/* ══════════════════════════════════════════════════════════════
   SUPABASE REST API LAYER
══════════════════════════════════════════════════════════════ */
const sbQ=async(path,opts={})=>{
  const method=opts.method||"GET";
  const prefer=opts.prefer!==undefined?opts.prefer:"return=representation";
  const headers={"apikey":SB_KEY,"Authorization":"Bearer "+SB_KEY};
  if(prefer)headers["Prefer"]=prefer;
  if(method!=="GET"&&method!=="DELETE")headers["Content-Type"]="application/json";
  const cfg={method,headers};
  if(opts.body)cfg.body=opts.body;
  const r=await fetch(SB_URL+"/rest/v1/"+path,cfg);
  if(!r.ok){const txt=await r.text();throw new Error("SB "+r.status+": "+txt);}
  const txt=await r.text();return txt?JSON.parse(txt):[];
};

/* ──────────────────────────────────────────────────────────────
   gdb  – read table (Supabase first, localStorage fallback)
   addR – insert row
   updR – update row by id
   delR – delete row by id
   uid  – generate unique id
────────────────────────────────────────────────────────────── */
const gdb=async(t,f="")=>{
  try{
    const d=await sbQ(t+"?order=created_at.asc"+(f?"&"+f:""));
    if(Array.isArray(d)){lsS(t,d);return d;}
    return lsG(t);
  }catch(e){
    console.warn("gdb fallback ["+t+"]:",e.message);
    return lsG(t);
  }
};
const addR=async(t,row)=>{
  const fallback={...row,id:row?.id||uid()};
  const upsertLocal=v=>{
    const c=lsG(t);
    const i=c.findIndex(x=>x&&x.id===v.id);
    if(i===-1)c.push(v); else c[i]={...c[i],...v};
    lsS(t,c);
  };
  try{
    const s=await sbQ(t,{method:"POST",body:JSON.stringify(row)});
    const r=Array.isArray(s)?s[0]:s;
    const final=(r&&r.id)?r:fallback;
    upsertLocal(final);
    return final;
  }catch(e){
    upsertLocal(fallback);
    console.warn("addR fallback ["+t+"]:",e.message);
    return fallback;
  }
};
const updR=async(t,id,p)=>{
  try{
    await sbQ(t+"?id=eq."+id,{method:"PATCH",body:JSON.stringify(p)});
  }catch(e){console.warn("updR ["+t+"]:",e.message);}
  lsS(t,lsG(t).map(r=>r.id===id?{...r,...p}:r));
};
const delR=async(t,id)=>{
  try{
    await sbQ(t+"?id=eq."+id,{method:"DELETE",prefer:""});
  }catch(e){console.warn("delR ["+t+"]:",e.message);}
  lsS(t,lsG(t).filter(r=>r.id!==id));
};
const uid=()=>"u"+Date.now()+Math.random().toString(36).slice(2,6);

/* ══════════════════════════════════════════════════════════════
   AUTH HELPERS
   loginUser(loginId, pass, role) → user object or null
   createUserAccount(role, loginId, pass) → saves to users table
══════════════════════════════════════════════════════════════ */
const loginUser=async(loginId,pass,role)=>{
  // loginId = SID for students, phone for teachers/parents, phone/email for admin
  const enc=encodeURIComponent;
  try{
    // Try Supabase first — match on phone OR email field, exact pass match
    const rows=await sbQ(
      "users?role=eq."+enc(role)
      +"&pass=eq."+enc(pass)
      +"&or=(phone.eq."+enc(loginId)+",email.eq."+enc(loginId)+")"
      +"&limit=1"
    );
    if(Array.isArray(rows)&&rows.length>0){
      lsS("session_user",JSON.stringify(rows[0]));
      return rows[0];
    }
    return null;
  }catch(e){
    console.warn("loginUser Supabase failed, trying cache:",e.message);
    // Fallback to localStorage cache
    const cached=lsG("users");
    const u=cached.find(u=>
      u.role===role&&u.pass===pass&&
      (u.phone===loginId||u.email===loginId||u.email===loginId+"@lg.edu"||u.email===loginId+"@parent.lg")
    );
    return u||null;
  }
};

const getSession=()=>{
  try{const s=localStorage.getItem("session_user");return s?JSON.parse(s):null;}
  catch{return null;}
};
const clearSession=()=>localStorage.removeItem("session_user");

