const seedSB=async()=>{
  if(localStorage.getItem("sb_admin_v3"))return;
  try{
    for(const[t,rows]of Object.entries(SEED)){
      const ex=await sbQ(t+"?limit=1").catch(()=>null);
      if(ex&&ex.length===0)for(const row of rows)
        await sbQ(t,{method:"POST",body:JSON.stringify(row)}).catch(()=>{});
    }
    localStorage.setItem("sb_admin_v3","1");
  }catch(e){console.warn("Seed err:",e.message);}
};

function initDB(){
  if(!localStorage.getItem("ls_admin_v3")){
    Object.entries(SEED).forEach(([t,rows])=>{
      if(lsG(t).length===0)lsS(t,rows);
    });
    localStorage.setItem("ls_admin_v3","1");
  }
  seedSB();
}


