/* ══════════════════════════════════════════════════════════════
   RIPPLE HOOK
══════════════════════════════════════════════════════════════ */
function useRipple(){
  const [rp,setRp]=useState([]);
  const add=useCallback(e=>{
    const r=e.currentTarget.getBoundingClientRect();
    const x=(e.clientX||r.left+r.width/2)-r.left;
    const y=(e.clientY||r.top+r.height/2)-r.top;
    const sz=Math.max(r.width,r.height)*2.2;
    const id=Date.now()+Math.random();
    setRp(p=>[...p,{id,x,y,sz}]);
    setTimeout(()=>setRp(p=>p.filter(r=>r.id!==id)),600);
  },[]);
  const el=rp.map(r=>(
    <span key={r.id} className="ripple-el"
      style={{width:r.sz,height:r.sz,left:r.x-r.sz/2,top:r.y-r.sz/2}}/>
  ));
  return [add,el];
}

/* ══════════════════════════════════════════════════════════════
   SHARED ATOMS
══════════════════════════════════════════════════════════════ */
function Btn({ch,onClick,color,outline,small,icon,disabled,className="",style:sx={}}){
  const [add,el]=useRipple();
  const bg=outline?"transparent":(color||C.accent);
  const br=outline?`2px solid ${color||C.accent}`:"none";
  const tc=outline?(color||C.accent):"#fff";
  return(
    <button onClick={e=>{if(!disabled){add(e);onClick&&onClick(e);}}} disabled={disabled}
      className={`btn ${className}`}
      style={{padding:small?"7px 16px":"10px 22px",borderRadius:12,border:br,
        background:disabled?"#E2E8F0":bg,color:disabled?C.sub:tc,
        fontWeight:700,fontSize:small?13:14,display:"inline-flex",alignItems:"center",
        gap:7,whiteSpace:"nowrap",opacity:disabled?.6:1,...sx}}>
      {el}{icon&&<span style={{fontSize:16}}>{icon}</span>}
      <span style={{position:"relative",zIndex:1}}>{ch}</span>
    </button>
  );
}

function Field({label,value,onChange,type="text",ph,opts,required,note,half}){
  const s={width:"100%",padding:"11px 14px",borderRadius:11,border:`1.5px solid ${C.border}`,
    background:C.light,color:C.text,fontSize:14,outline:"none",transition:"border .2s, box-shadow .2s",
    fontFamily:"'Poppins',sans-serif"};
  const focus=e=>{e.target.style.borderColor=C.accent;e.target.style.boxShadow=`0 0 0 3px ${C.accent}18`;};
  const blur =e=>{e.target.style.borderColor=C.border;e.target.style.boxShadow="none";};
  return(
    <div style={{marginBottom:14,width:half?"calc(50% - 6px)":"100%"}}>
      {label&&<label style={{display:"block",fontSize:12,fontWeight:700,color:C.sub,marginBottom:6}}>
        {label}{required&&<span style={{color:C.red}}>*</span>}
      </label>}
      {opts
        ?<select value={value} onChange={e=>onChange(e.target.value)} style={s} onFocus={focus} onBlur={blur}>
          <option value="">Select…</option>
          {opts.map(o=><option key={o.v??o} value={o.v??o}>{o.l??o}</option>)}
        </select>
        :type==="textarea"
          ?<textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={ph} rows={3}
              style={{...s,resize:"vertical"}} onFocus={focus} onBlur={blur}/>
          :<input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={ph}
              style={s} onFocus={focus} onBlur={blur} required={required}/>
      }
      {note&&<div style={{fontSize:11,color:C.sub,marginTop:4}}>{note}</div>}
    </div>
  );
}

