function TopBar({title,subtitle,action}){
  return(
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",
      padding:"20px 28px",background:"#fff",borderBottom:`1px solid ${C.border}`,flexShrink:0}}>
      <div>
        <div style={{fontSize:20,fontWeight:800,color:C.text}}>{title}</div>
        {subtitle&&<div style={{fontSize:13,color:C.sub,marginTop:2}}>{subtitle}</div>}
      </div>
      {action}
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   TABLE COMPONENT
══════════════════════════════════════════════════════════════ */
function Table({cols,rows,empty="No records found"}){
  return(
    <div style={{overflowX:"auto"}}>
      <table style={{width:"100%",borderCollapse:"collapse",fontSize:14}}>
        <thead>
          <tr style={{background:C.light}}>
            {cols.map(c=><th key={c.k} style={{textAlign:"left",padding:"12px 16px",color:C.sub,fontWeight:700,fontSize:12,borderBottom:`2px solid ${C.border}`,whiteSpace:"nowrap"}}>{c.label}</th>)}
          </tr>
        </thead>
        <tbody>
          {rows.length===0
            ?<tr><td colSpan={cols.length} style={{textAlign:"center",padding:40,color:C.sub,fontSize:14}}>{empty}</td></tr>
            :rows.map((r,i)=>(
              <tr key={i} className="row-hover" style={{borderBottom:`1px solid ${C.border}`}}>
                {cols.map(c=><td key={c.k} style={{padding:"12px 16px",color:C.text,verticalAlign:"middle"}}>{c.render?c.render(r):r[c.k]}</td>)}
              </tr>
            ))
          }
        </tbody>
      </table>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   CONFIRM DIALOG
══════════════════════════════════════════════════════════════ */
function Confirm({open,msg,onYes,onNo}){
  if(!open)return null;
  return(
    <div className="modal-backdrop" style={{position:"fixed",inset:0,background:"rgba(15,27,61,.6)",zIndex:2000,display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div className="modal-box" style={{background:"#fff",borderRadius:20,padding:28,width:340,textAlign:"center",boxShadow:"0 24px 60px rgba(15,27,61,.2)"}}>
        <div style={{fontSize:36,marginBottom:12}}>⚠️</div>
        <div style={{fontSize:16,fontWeight:700,color:C.text,marginBottom:8}}>Are you sure?</div>
        <div style={{fontSize:13,color:C.sub,marginBottom:22}}>{msg}</div>
        <div style={{display:"flex",gap:10,justifyContent:"center"}}>
          <Btn ch="Cancel" onClick={onNo} outline color={C.sub}/>
          <Btn ch="Delete" onClick={onYes} color={C.red} className="btn-danger"/>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   LOGIN
══════════════════════════════════════════════════════════════ */
function AdminLogin({onLogin}){
  const [phone,setPhone]=useState("");
  const [pass,setPass]=useState("");
  const [err,setErr]=useState("");
  const [loading,setLoading]=useState(false);
  const [showP,setShowP]=useState(false);
  const handle=async()=>{
    if(!phone||!pass){setErr("Fill all fields.");return;}
    setLoading(true);setErr("");
    try{
      // Try DB lookup first
      let u=await loginUser(phone,pass,"admin");
      // Hardcoded fallback — always works even if DB is down
      if(!u&&phone==="9265628247"&&pass==="SapanRohera82"){
        u={id:"u0",name:"Admin",phone:"9265628247",role:"admin",status:"active"};
      }
      setLoading(false);
      if(u)onLogin(u);
      else setErr("Wrong credentials. Use: 9265628247 / SapanRohera82");
    }catch(e){
      // Network error — always allow hardcoded admin
      if(phone==="9265628247"&&pass==="SapanRohera82"){
        onLogin({id:"u0",name:"Admin",phone:"9265628247",role:"admin",status:"active"});
      } else {
        setLoading(false);
        setErr("Connection error. Try again.");
      }
    }
  };
  return(
    <div style={{minHeight:"100vh",background:"linear-gradient(160deg,#0d1f4e 0%,#122466 50%,#0a1835 100%)",
      display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Poppins',sans-serif",padding:16}}>
      <style>{CSS}</style>
      <div className="zi" style={{width:"100%",maxWidth:420}}>
        {/* Logo */}
        <div style={{textAlign:"center",marginBottom:32}}>
          <div style={{display:"flex",justifyContent:"center",marginBottom:10}}>
            <div style={{width:72,height:72,borderRadius:20,background:"#fff",
              display:"flex",alignItems:"center",justifyContent:"center",
              overflow:"hidden",padding:5,
              boxShadow:"0 8px 32px rgba(0,0,0,0.3)"}}>
              <img src={LOGO_IMG_SRC} alt="Learner's Guide" style={{width:"100%",height:"100%",objectFit:"contain"}}/>
            </div>
          </div>
          <div style={{fontSize:26,fontWeight:900,color:"#fff"}}>Learner's <span style={{color:C.gold}}>Guide</span></div>
          <div style={{marginTop:8,display:"inline-flex",alignItems:"center",gap:6,
            background:"rgba(239,68,68,.2)",borderRadius:20,padding:"4px 14px"}}>
            <span style={{fontSize:12,color:"#FF8080",fontWeight:700}}>👑 ADMIN PANEL</span>
          </div>
        </div>
        {/* Card */}
        <div style={{background:"rgba(255,255,255,.06)",borderRadius:24,padding:"28px 26px",
          backdropFilter:"blur(20px)",border:"1.5px solid rgba(255,255,255,.1)"}}>
          <div style={{fontSize:16,fontWeight:800,color:"#fff",marginBottom:20}}>Sign In to Admin</div>
          {/* Phone */}
          <div style={{marginBottom:14}}>
            <div style={{fontSize:13,fontWeight:700,color:"rgba(255,255,255,.7)",marginBottom:7}}>Phone / Email</div>
            <input value={phone} onChange={e=>setPhone(e.target.value)} placeholder="Admin phone or email"
              style={{width:"100%",padding:"13px 16px",borderRadius:13,border:"1.5px solid rgba(255,255,255,.15)",
                background:"rgba(255,255,255,.1)",color:"#fff",fontSize:15,outline:"none",fontFamily:"'Poppins',sans-serif"}}
              onFocus={e=>e.target.style.borderColor="rgba(255,255,255,.6)"}
              onBlur={e=>e.target.style.borderColor="rgba(255,255,255,.15)"}/>
          </div>
          {/* Pass */}
          <div style={{marginBottom:20}}>
            <div style={{fontSize:13,fontWeight:700,color:"rgba(255,255,255,.7)",marginBottom:7}}>Password</div>
            <div style={{position:"relative"}}>
              <input type={showP?"text":"password"} value={pass} onChange={e=>setPass(e.target.value)} placeholder="Admin password"
                onKeyDown={e=>e.key==="Enter"&&handle()}
                style={{width:"100%",padding:"13px 46px 13px 16px",borderRadius:13,border:"1.5px solid rgba(255,255,255,.15)",
                  background:"rgba(255,255,255,.1)",color:"#fff",fontSize:15,outline:"none",fontFamily:"'Poppins',sans-serif"}}
                onFocus={e=>e.target.style.borderColor="rgba(255,255,255,.6)"}
                onBlur={e=>e.target.style.borderColor="rgba(255,255,255,.15)"}/>
              <span onClick={()=>setShowP(s=>!s)} style={{position:"absolute",right:14,top:"50%",transform:"translateY(-50%)",cursor:"pointer",color:"rgba(255,255,255,.5)",fontSize:18}}>{showP?"🙈":"👁️"}</span>
            </div>
          </div>
          {err&&<div className="fu" style={{background:"rgba(239,68,68,.2)",color:"#FCA5A5",padding:"10px 14px",borderRadius:10,fontSize:13,marginBottom:14}}>{err}</div>}
          <Btn ch={loading?<><span className="spin">⟳</span> Signing in…</>:"Login to Admin Panel 👑"}
            onClick={handle} dis={loading}
            style={{width:"100%",justifyContent:"center",padding:"14px",borderRadius:14,fontSize:15,background:"#fff",color:"#0d1f4e"}}/>
          <div style={{marginTop:16,background:"rgba(255,255,255,.07)",borderRadius:11,padding:"10px 14px"}}>
            <div style={{fontSize:11,color:"rgba(255,255,255,.35)",fontWeight:700,marginBottom:4}}>DEMO ADMIN</div>
            <div onClick={()=>{setPhone("9265628247");setPass("SapanRohera82");}} style={{fontSize:12,color:"rgba(255,255,255,.55)",cursor:"pointer",padding:"4px 0"}}>
              📋 Phone: 9265628247 · Pass: SapanRohera82
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   DASHBOARD
══════════════════════════════════════════════════════════════ */
function Dashboard(){
  const students=lsG("students");
  const teachers=lsG("teachers");
  const att=lsG("attendance");
  const fees=lsG("fees");
  const ann=lsG("announcements");
  const hw=lsG("homework");
  const present=att.filter(a=>a.status==="present").length;
  const attRate=att.length?Math.round((present/att.length)*100):0;
  const pending=fees.filter(f=>f.status!=="paid");
  const pendingAmt=pending.reduce((s,f)=>s+Number(f.amount),0);
  const paid=fees.filter(f=>f.status==="paid").reduce((s,f)=>s+Number(f.amount),0);

  // mini bar chart
  const days=["Mon","Tue","Wed","Thu","Fri"];
  const bars=days.map(d=>({d,v:60+Math.floor(Math.random()*35)}));
  const mx=Math.max(...bars.map(b=>b.v));

  return(
    <div style={{padding:28,overflowY:"auto"}}>
      {/* Stats row */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(170px,1fr))",gap:16,marginBottom:24}}>
        <StatCard icon="🎓" label="Total Students"   val={students.length} color={C.accent} sub={`${students.filter(s=>s.status==="active").length} active`} animClass="fu d1"/>
        <StatCard icon="👨‍🏫" label="Teachers"         val={teachers.length} color={C.purple} sub="All active"  animClass="fu d2"/>
        <StatCard icon="✅" label="Attendance Rate"  val={`${attRate}%`}    color={C.green}  sub={`${present}/${att.length} records`} animClass="fu d3"/>
        <StatCard icon="💰" label="Pending Fees"     val={pending.length}   color={C.red}    sub={`₹${pendingAmt.toLocaleString()}`} animClass="fu d4"/>
        <StatCard icon="📝" label="Active Homework"  val={hw.length}        color={C.gold}   animClass="fu d5"/>
        <StatCard icon="📢" label="Announcements"    val={ann.length}       color={C.cyan}   animClass="fu d6"/>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,marginBottom:20}}>
        {/* Chart */}
        <div className="fu d2" style={{background:"#fff",borderRadius:20,padding:24,boxShadow:"0 4px 20px rgba(15,27,61,.07)",border:"1px solid #EEF2FF"}}>
          <div style={{fontWeight:800,color:C.text,fontSize:15,marginBottom:4}}>Weekly Attendance Trend 📊</div>
          <div style={{fontSize:12,color:C.sub,marginBottom:18}}>This week's presence rate</div>
          <div style={{display:"flex",alignItems:"flex-end",gap:10,height:100}}>
            {bars.map(b=>(
              <div key={b.d} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:6}}>
                <div style={{fontSize:11,fontWeight:700,color:C.accent}}>{b.v}%</div>
                <div style={{width:"100%",height:72,display:"flex",alignItems:"flex-end"}}>
                  <div style={{width:"100%",height:`${(b.v/mx)*100}%`,background:`linear-gradient(180deg,${C.accent},#7B91F5)`,borderRadius:"6px 6px 0 0",transition:"height .5s ease"}}/>
                </div>
                <div style={{fontSize:11,color:C.sub}}>{b.d}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Fee summary */}
        <div className="fu d3" style={{background:"#fff",borderRadius:20,padding:24,boxShadow:"0 4px 20px rgba(15,27,61,.07)",border:"1px solid #EEF2FF"}}>
          <div style={{fontWeight:800,color:C.text,fontSize:15,marginBottom:16}}>Fee Collection 💰</div>
          {[["Collected","#22C55E",paid],["Pending","#F59E0B",fees.filter(f=>f.status==="pending").reduce((s,f)=>s+f.amount,0)],["Overdue","#EF4444",fees.filter(f=>f.status==="overdue").reduce((s,f)=>s+f.amount,0)]].map(([l,c,v])=>(
            <div key={l} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 0",borderBottom:`1px solid ${C.border}`}}>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:10,height:10,borderRadius:"50%",background:c}}/>
                <span style={{fontSize:14,color:C.text,fontWeight:600}}>{l}</span>
              </div>
              <span style={{fontSize:15,fontWeight:800,color:c}}>₹{v.toLocaleString()}</span>
            </div>
          ))}
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20}}>
        {/* Recent students */}
        <div className="fu d4" style={{background:"#fff",borderRadius:20,padding:24,boxShadow:"0 4px 20px rgba(15,27,61,.07)",border:"1px solid #EEF2FF"}}>
          <div style={{fontWeight:800,color:C.text,fontSize:15,marginBottom:16}}>Recent Students 🎓</div>
          {students.slice(0,4).map(s=>(
            <div key={s.id} style={{display:"flex",alignItems:"center",gap:12,padding:"9px 0",borderBottom:`1px solid ${C.border}`}}>
              <div style={{width:36,height:36,borderRadius:11,background:C.accent+"18",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800,color:C.accent,fontSize:14}}>{s.name[0]}</div>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,color:C.text,fontSize:13}}>{s.name}</div>
                <div style={{fontSize:11,color:C.sub}}>Class {s.cls}-{s.sec} · {s.sid}</div>
              </div>
              <Badge label={s.status}/>
            </div>
          ))}
        </div>

        {/* Announcements */}
        <div className="fu d5" style={{background:"#fff",borderRadius:20,padding:24,boxShadow:"0 4px 20px rgba(15,27,61,.07)",border:"1px solid #EEF2FF"}}>
          <div style={{fontWeight:800,color:C.text,fontSize:15,marginBottom:16}}>Latest Announcements 📢</div>
          {ann.slice(0,4).map(a=>(
            <div key={a.id} style={{padding:"10px 0",borderBottom:`1px solid ${C.border}`}}>
              <div style={{fontWeight:700,color:C.text,fontSize:13,marginBottom:3}}>{a.title}</div>
              <div style={{display:"flex",gap:8,alignItems:"center"}}>
                <Badge label={a.target}/><span style={{fontSize:11,color:C.sub}}>{a.date}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   STUDENTS  (the most important — creates parent account too)
══════════════════════════════════════════════════════════════ */
function Students(){
  const [list,setList]=useState(lsG("students"));
  const [modal,setModal]=useState(false);
  const [editId,setEditId]=useState(null);
  const [confirm,setConfirm]=useState(null);
  const [search,setSearch]=useState("");
  const [filterCls,setFilterCls]=useState("");
  const blank={name:"",sid:"",cls:"",sec:"",parentName:"",parentPhone:"",enroll:new Date().toISOString().split("T")[0],status:"active",pass:"1234"};
  const [form,setForm]=useState(blank);
  const [success,setSuccess]=useState("");
  const refresh=async()=>{const d=await gdb("students");setList(d);};
  const f=v=>({...form,...v});

  const autoSid=()=>{
    const existing=lsG("students");
    const num=existing.length+1;
    return `LG${String(num).padStart(3,"0")}`;
  };

  const openAdd=()=>{setForm({...blank,sid:autoSid()});setEditId(null);setModal(true);};
  const openEdit=s=>{setForm(s);setEditId(s.id);setModal(true);};

  const save= async()=>{try{
    if(!form.name||!form.cls||!form.sec||!form.parentPhone){alert("Fill all required fields.");return;}
    const users=lsG("users");
    if(editId){
      // Update student
      await updR("students",editId,form);
      // Update parent user link
      const pu=users.find(u=>u.role==="parent"&&u.ref===editId);
      if(pu){ await updR("users",pu.id,{name:form.parentName,phone:form.parentPhone}); }
    } else {
      // Add student record
      const newStudent={...form,id:"s"+Date.now()};
      await addR("students",newStudent);
      // Create student user account
      // Student login: SID as phone (e.g. LG001), password set by admin
      const stuUser={
        id:uid(),name:form.name,
        phone:form.sid,          // student logs in with their SID
        email:form.sid+"@lg.edu",
        pass:form.pass||"1234",
        role:"student",ref:newStudent.id,status:"active"
      };
      // Parent login: parentPhone + "parent@1234" (or set by admin)
      const parUser={
        id:uid(),name:form.parentName,
        phone:form.parentPhone,   // parent logs in with their phone
        email:form.parentPhone+"@parent.lg",
        pass:"parent@1234",
        role:"parent",ref:newStudent.id,status:"active"
      };
      await addR("users",stuUser);
      await addR("users",parUser);
    }
    await refresh();setModal(false);
    setSuccess(editId?"Student updated successfully!":"Student added! Parent account auto-created ✅");
    setTimeout(()=>setSuccess(""),3500);
  }catch(e){alert("Error saving student: "+e.message);}};

  const del=async(id)=>{try{await delR("students",id);for(const u of lsG("users").filter(u=>u.ref===id)) await delR("users",u.id);await refresh();setConfirm(null);}catch(e){alert("Error deleting: "+e.message);}};

  const filtered=list.filter(s=>
    (s.name.toLowerCase().includes(search.toLowerCase())||s.sid.includes(search))
    &&(!filterCls||s.cls===filterCls)
  );

  return(
    <div style={{padding:28,overflowY:"auto"}}>
      <style>{CSS}</style>
      {success&&<div className="fu" style={{background:"#DCFCE7",borderRadius:14,padding:"12px 18px",marginBottom:18,color:"#16A34A",fontWeight:700,fontSize:14,display:"flex",alignItems:"center",gap:8}}>
        <span className="tick-pop">✅</span>{success}
      </div>}

      {/* Filters + Add */}
      <div style={{display:"flex",gap:12,alignItems:"center",marginBottom:20,flexWrap:"wrap"}}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Search by name or ID…"
          style={{flex:1,minWidth:180,padding:"10px 16px",borderRadius:12,border:`1.5px solid ${C.border}`,background:"#fff",color:C.text,fontSize:14,outline:"none",fontFamily:"'Poppins',sans-serif"}}/>
        <select value={filterCls} onChange={e=>setFilterCls(e.target.value)}
          style={{padding:"10px 14px",borderRadius:12,border:`1.5px solid ${C.border}`,background:"#fff",color:C.text,fontSize:14,outline:"none",fontFamily:"'Poppins',sans-serif"}}>
          <option value="">All Classes</option>
          {[...new Set(list.map(s=>s.cls))].map(c=><option key={c}>Class {c}</option>)}
        </select>
        <Btn ch="+ Add Student" onClick={openAdd} icon="🎓"/>
      </div>

      {/* Table */}
      <div style={{background:"#fff",borderRadius:20,boxShadow:"0 4px 20px rgba(15,27,61,.07)",border:"1px solid #EEF2FF",overflow:"hidden"}}>
        <Table cols={[
          {k:"sid",   label:"Roll No"},
          {k:"name",  label:"Student Name"},
          {k:"cls",   label:"Class",render:r=>`${r.cls}-${r.sec}`},
          {k:"parentName", label:"Parent Name"},
          {k:"parentPhone",label:"Parent Phone"},
          {k:"status",label:"Status",render:r=><Badge label={r.status}/>},
          {k:"login", label:"Login ID",render:r=><span style={{fontSize:12,color:C.sub,fontFamily:"monospace"}}>{r.sid}</span>},
          {k:"act",   label:"Actions",render:r=>(
            <div style={{display:"flex",gap:6}}>
              <Btn ch="Edit" onClick={()=>openEdit(r)} small outline color={C.accent}/>
              <Btn ch="🗑" onClick={()=>setConfirm(r.id)} small color={C.red} className="btn-danger"/>
            </div>
          )},
        ]} rows={filtered}/>
      </div>

      {/* Add/Edit Modal */}
      <Modal open={modal} onClose={()=>setModal(false)} title={editId?"Edit Student":"Add New Student"} wide>
        <div style={{background:"#F0F9FF",borderRadius:14,padding:"12px 16px",marginBottom:20,fontSize:13,color:"#0284C7",fontWeight:600}}>
          ℹ️ {editId?"Edit student details below."
            :"When you add a student, the system automatically creates:\n• Student login (Roll No + password)\n• Parent login (Parent phone + password)"}
        </div>
        {/* Student Info */}
        <div style={{fontSize:13,fontWeight:800,color:C.text,marginBottom:12,padding:"6px 0",borderBottom:`2px solid ${C.border}`}}>👨‍🎓 Student Information</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:12}}>
          <Field label="Full Name" value={form.name} onChange={v=>setForm(f({name:v}))} ph="Student full name" required half/>
          <Field label="Roll Number (Login ID)" value={form.sid} onChange={v=>setForm(f({sid:v}))} ph="e.g. LG001" required half/>
          <Field label="Class" value={form.cls} onChange={v=>setForm(f({cls:v}))} opts={["9","10","11","12"]} required half/>
          <Field label="Section" value={form.sec} onChange={v=>setForm(f({sec:v}))} opts={["A","B","C","D"]} required half/>
          <Field label="Enrollment Date" type="date" value={form.enroll} onChange={v=>setForm(f({enroll:v}))} half/>
          <Field label="Status" value={form.status} onChange={v=>setForm(f({status:v}))} opts={["active","inactive"]} half/>
          <Field label="Student Password" value={form.pass} onChange={v=>setForm(f({pass:v}))} ph="Default: 1234" half note="Student will login with Roll No + this password"/>
        </div>
        {/* Parent Info */}
        <div style={{fontSize:13,fontWeight:800,color:C.text,margin:"18px 0 12px",padding:"6px 0",borderBottom:`2px solid ${C.border}`}}>👨‍👩‍👧 Parent Information</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:12}}>
          <Field label="Parent / Guardian Name" value={form.parentName} onChange={v=>setForm(f({parentName:v}))} ph="Parent full name" required half/>
          <Field label="Parent Phone (Login)" value={form.parentPhone} onChange={v=>setForm(f({parentPhone:v}))} ph="10-digit mobile" required half note="Parent logs in with this phone number. Auto-linked to this student only."/>
        </div>
        <div style={{background:"#FFF7ED",borderRadius:12,padding:"10px 14px",marginBottom:20,fontSize:12,color:"#92400E",fontWeight:600}}>
          🔒 Parent default password: <strong>parent@1234</strong> — they can change it after first login.
        </div>
        <div style={{display:"flex",gap:10,justifyContent:"flex-end"}}>
          <Btn ch="Cancel" onClick={()=>setModal(false)} outline color={C.sub}/>
          <Btn ch={editId?"Save Changes":"Add Student + Create Accounts"} onClick={save} icon={editId?"✅":"🎓"}/>
        </div>
      </Modal>

      <Confirm open={!!confirm} msg="This will delete the student and their parent account permanently."
        onYes={()=>del(confirm)} onNo={()=>setConfirm(null)}/>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   TEACHERS
══════════════════════════════════════════════════════════════ */
function Teachers(){
  const [list,setList]=useState(lsG("teachers"));
  const [modal,setModal]=useState(false);
  const [editId,setEditId]=useState(null);
  const [confirm,setConfirm]=useState(null);
  const blank={name:"",tid:"",subject:"",phone:"",status:"active",pass:"1234",classes:[]};
  const [form,setForm]=useState(blank);
  const [success,setSuccess]=useState("");
  const refresh=async()=>{const d=await gdb("teachers");setList(d);};
  const f=v=>({...form,...v});

  const autoTid=()=>`LGT${String(lsG("teachers").length+1).padStart(2,"0")}`;

  const save= async()=>{try{
    if(!form.name||!form.phone||!form.subject){alert("Fill all required fields.");return;}
    const users=lsG("users");
    if(editId){
      await updR("teachers",editId,form);
      const tu=users.find(u=>u.role==="teacher"&&u.ref===editId);
      if(tu) await updR("users",tu.id,{name:form.name,phone:form.phone});
    } else {
      const newT={...form,id:"t"+Date.now()};
      await addR("teachers",newT);
      // Teacher login: phone number + password
      const tu={
        id:uid(),name:form.name,
        phone:form.phone,         // teacher logs in with phone
        email:form.phone+"@lg.edu",
        pass:form.pass||"1234",
        role:"teacher",ref:newT.id,status:"active"
      };
      await addR("users",tu);
    }
    await refresh();setModal(false);
    setSuccess(editId?"Teacher updated!":"Teacher added! Login account created ✅");
    setTimeout(()=>setSuccess(""),3000);
  }catch(e){alert("Error saving teacher: "+e.message);}};

  const del=async(id)=>{try{await delR("teachers",id);for(const u of lsG("users").filter(u=>u.ref===id)) await delR("users",u.id);await refresh();setConfirm(null);}catch(e){alert("Error deleting: "+e.message);}};

  return(
    <div style={{padding:28,overflowY:"auto"}}>
      {success&&<div className="fu" style={{background:"#DCFCE7",borderRadius:14,padding:"12px 18px",marginBottom:18,color:"#16A34A",fontWeight:700,fontSize:14}}><span className="tick-pop">✅</span> {success}</div>}
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:18}}>
        <Btn ch="+ Add Teacher" onClick={()=>{setForm({...blank,tid:autoTid()});setEditId(null);setModal(true);}} icon="👨‍🏫"/>
      </div>
      <div style={{background:"#fff",borderRadius:20,boxShadow:"0 4px 20px rgba(15,27,61,.07)",border:"1px solid #EEF2FF",overflow:"hidden"}}>
        <Table cols={[
          {k:"tid",     label:"Teacher ID"},
          {k:"name",    label:"Name"},
          {k:"subject", label:"Subject"},
          {k:"phone",   label:"Phone (Login)"},
          {k:"classes", label:"Assigned Classes",render:r=><span style={{fontSize:12}}>{(r.classes||[]).join(", ")||"—"}</span>},
          {k:"status",  label:"Status",render:r=><Badge label={r.status}/>},
          {k:"act",     label:"Actions",render:r=>(
            <div style={{display:"flex",gap:6}}>
              <Btn ch="Edit" onClick={()=>{setForm(r);setEditId(r.id);setModal(true);}} small outline color={C.accent}/>
              <Btn ch="🗑" onClick={()=>setConfirm(r.id)} small color={C.red} className="btn-danger"/>
            </div>
          )},
        ]} rows={list}/>
      </div>
      <Modal open={modal} onClose={()=>setModal(false)} title={editId?"Edit Teacher":"Add New Teacher"}>
        <Field label="Full Name" value={form.name} onChange={v=>setForm(f({name:v}))} ph="Teacher name" required/>
        <Field label="Teacher ID" value={form.tid} onChange={v=>setForm(f({tid:v}))} ph="e.g. LGT01" required/>
        <Field label="Subject" value={form.subject} onChange={v=>setForm(f({subject:v}))} opts={["Mathematics","Science","English","History","Geography","Computer","Hindi"]} required/>
        <Field label="Phone (Login ID)" value={form.phone} onChange={v=>setForm(f({phone:v}))} ph="10-digit mobile" required note="Teacher logs in with this phone number"/>
        <Field label="Password" value={form.pass} onChange={v=>setForm(f({pass:v}))} ph="Default: 1234"/>
        <Field label="Status" value={form.status} onChange={v=>setForm(f({status:v}))} opts={["active","inactive"]}/>
        <div style={{display:"flex",gap:10,justifyContent:"flex-end",marginTop:8}}>
          <Btn ch="Cancel" onClick={()=>setModal(false)} outline color={C.sub}/>
          <Btn ch={editId?"Save Changes":"Add Teacher"} onClick={save} icon="✅"/>
        </div>
      </Modal>
      <Confirm open={!!confirm} msg="Delete this teacher and their account?" onYes={()=>del(confirm)} onNo={()=>setConfirm(null)}/>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   TIMETABLE
══════════════════════════════════════════════════════════════ */
function Timetable(){
  const [tt,setTt]=useState(lsG("timetable"));
  const [modal,setModal]=useState(false);
  const [form,setForm]=useState({cls:"10",sec:"A",subject:"",tid:"",day:"Monday",slot:"8:00–9:00 AM"});
  const teachers=lsG("teachers");
  const refresh=async()=>{const d=await gdb("timetable");setTt(d);};
  const days=["Monday","Tuesday","Wednesday","Thursday","Friday"];
  const slots=["8:00–9:00 AM","9:00–10:00 AM","10:00–11:00 AM","11:00 AM–12:00 PM","12:00–1:00 PM","1:00–2:00 PM"];
  const save=async()=>{try{await addR("timetable",{...form,id:"tt"+Date.now()});await refresh();setModal(false);}catch(e){alert("Error saving slot: "+e.message);}};
  const getTeacher=id=>teachers.find(t=>t.id===id)?.name||id;
  const clsGroups=[...new Set(tt.map(t=>`${t.cls}-${t.sec}`))];

  return(
    <div style={{padding:28,overflowY:"auto"}}>
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:18}}>
        <Btn ch="+ Add Slot" onClick={()=>setModal(true)} icon="📅"/>
      </div>
      {clsGroups.map(clg=>(
        <div key={clg} style={{marginBottom:24}}>
          <div style={{fontSize:15,fontWeight:800,color:C.text,marginBottom:12,display:"flex",alignItems:"center",gap:10}}>
            <span style={{background:C.accent,color:"#fff",padding:"4px 14px",borderRadius:20,fontSize:13}}>Class {clg}</span>
          </div>
          {days.map(day=>{
            const slots2=tt.filter(t=>t.cls===clg.split("-")[0]&&t.sec===clg.split("-")[1]&&t.day===day);
            if(!slots2.length)return null;
            return(
              <div key={day} style={{marginBottom:10}}>
                <div style={{fontSize:12,fontWeight:700,color:C.accent,marginBottom:6,padding:"4px 12px",background:C.accent+"12",borderRadius:8,display:"inline-block"}}>{day}</div>
                <div style={{background:"#fff",borderRadius:14,border:`1px solid ${C.border}`,overflow:"hidden"}}>
                  {slots2.map(s=>(
                    <div key={s.id} style={{display:"flex",alignItems:"center",gap:16,padding:"12px 18px",borderBottom:`1px solid ${C.border}`}}>
                      <div style={{width:140,fontSize:13,color:C.sub,fontWeight:600,flexShrink:0}}>{s.slot}</div>
                      <div style={{fontWeight:700,color:C.text,fontSize:14,flex:1}}>{s.subject}</div>
                      <div style={{fontSize:13,color:C.sub}}>{getTeacher(s.tid)}</div>
                      <button onClick={async()=>{await delR("timetable",s.id);refresh();}} className="btn btn-danger" style={{background:"#FEE2E2",border:"none",borderRadius:8,padding:"5px 10px",color:C.red,cursor:"pointer",fontSize:14}}>🗑</button>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      ))}
      <Modal open={modal} onClose={()=>setModal(false)} title="Add Timetable Slot">
        <div style={{display:"flex",gap:12}}>
          <Field label="Class" value={form.cls} onChange={v=>setForm({...form,cls:v})} opts={["9","10","11","12"]} required half/>
          <Field label="Section" value={form.sec} onChange={v=>setForm({...form,sec:v})} opts={["A","B","C","D"]} required half/>
        </div>
        <Field label="Subject" value={form.subject} onChange={v=>setForm({...form,subject:v})} opts={["Mathematics","Science","English","History","Geography","Computer","Hindi"]}/>
        <Field label="Teacher" value={form.tid} onChange={v=>setForm({...form,tid:v})} opts={teachers.map(t=>({v:t.id,l:t.name}))}/>
        <Field label="Day" value={form.day} onChange={v=>setForm({...form,day:v})} opts={days}/>
        <Field label="Time Slot" value={form.slot} onChange={v=>setForm({...form,slot:v})} opts={slots}/>
        <div style={{display:"flex",gap:10,justifyContent:"flex-end"}}>
          <Btn ch="Cancel" onClick={()=>setModal(false)} outline color={C.sub}/>
          <Btn ch="Add Slot" onClick={save} icon="✅"/>
        </div>
      </Modal>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   ATTENDANCE REPORT
══════════════════════════════════════════════════════════════ */
function AttendanceReport(){
  const att=lsG("attendance");
  const students=lsG("students");
  const [filterSid,setFilterSid]=useState("");
  const [filterDate,setFilterDate]=useState("");

  const filtered=att.filter(a=>
    (!filterSid||a.sid===filterSid)&&(!filterDate||a.date===filterDate)
  );
  const getName=id=>students.find(s=>s.id===id)?.name||id;
  const present=att.filter(a=>a.status==="present").length;
  const rate=att.length?Math.round((present/att.length)*100):0;

  return(
    <div style={{padding:28,overflowY:"auto"}}>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))",gap:14,marginBottom:22}}>
        <StatCard icon="✅" label="Present"  val={att.filter(a=>a.status==="present").length} color={C.green}/>
        <StatCard icon="❌" label="Absent"   val={att.filter(a=>a.status==="absent").length}  color={C.red}/>
        <StatCard icon="🟡" label="Leave"    val={att.filter(a=>a.status==="leave").length}   color={C.amber}/>
        <StatCard icon="📊" label="Avg Rate" val={`${rate}%`} color={C.accent}/>
      </div>
      <div style={{display:"flex",gap:12,marginBottom:18,flexWrap:"wrap"}}>
        <select value={filterSid} onChange={e=>setFilterSid(e.target.value)}
          style={{padding:"10px 14px",borderRadius:12,border:`1.5px solid ${C.border}`,background:"#fff",color:C.text,fontSize:14,outline:"none",fontFamily:"'Poppins',sans-serif"}}>
          <option value="">All Students</option>
          {students.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
        </select>
        <input type="date" value={filterDate} onChange={e=>setFilterDate(e.target.value)}
          style={{padding:"10px 14px",borderRadius:12,border:`1.5px solid ${C.border}`,background:"#fff",color:C.text,fontSize:14,outline:"none",fontFamily:"'Poppins',sans-serif"}}/>
        {(filterSid||filterDate)&&<Btn ch="Clear" onClick={()=>{setFilterSid("");setFilterDate("");}} outline color={C.sub} small/>}
      </div>
      <div style={{background:"#fff",borderRadius:20,boxShadow:"0 4px 20px rgba(15,27,61,.07)",border:"1px solid #EEF2FF",overflow:"hidden"}}>
        <Table cols={[
          {k:"sid",    label:"Student",render:r=>getName(r.sid)},
          {k:"date",   label:"Date"},
          {k:"status", label:"Status",render:r=><Badge label={r.status}/>},
          {k:"by",     label:"Marked By",render:r=>lsG("teachers").find(t=>t.id===r.by)?.name||"—"},
        ]} rows={[...filtered].reverse()}/>
      </div>
    </div>
  );
}

